#include <bits/stdc++.h>
using namespace std;
int dp[128],a,p,l,t[128];
long long sum=0;
string s;
int main(){
    cin>>p>>s;
    l=s.size();
    for(int i=1;i<=l;i++){
        a=s[i-1]-'0';
        a%=p;
        for(int j=0;j<p;j++)t[j]=dp[j],dp[j]=0;
        for(int j=0;j<p;j++)dp[(10*j+a)%p]+=t[j];
        dp[a]++;
        sum+=dp[0];
    }
    cout<<sum;
    return 0;
}
